package be.schaubroeck.lpb.rkm.rekenmotor.rsz.pensioenpijler2.validatie;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.pensioenpijler2.validatie.PensioenPijler2ValidatorDmfa;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.pensioenpijler2.validatie.PensioenPijler2ValidatorDmfa2023;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl.bijdrage.patronaal.pensioenpijler2.validatie.PensioenPijler2ValidatorDmfapplPre2010;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

@AllArgsConstructor
public class PensioenPijler2ValidatorFactory {
    private static final LocalDate START_2010 = new LocalDate(2010, 1, 1);
    private static final LocalDate START_DMFA = new LocalDate(2022, 1, 1);
    private static final LocalDate START_2023 = new LocalDate(2023, 1, 1);

    private ConstantManager constantManager;
    private DmfapplBasisBijdrageService dmfapplBasisBijdrageService;

    public PensioenPijler2Validator create(Opper opper, RekenTijd rekenTijd, RegulManager regulManager) {
        AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenTijd);
        if (tijdperk == AkeTijdperk.DMFAPPL) {
            return createDmfappl(opper, rekenTijd, regulManager);
        } else {
            return new PensioenPijler2ValidatorGeen();
        }
    }

    private PensioenPijler2Validator createDmfappl(Opper opper, RekenTijd rekenTijd, RegulManager regulManager) {
        if (rekenTijd.eindDatum.isBefore(START_2010)) {
            return new PensioenPijler2ValidatorDmfapplPre2010(opper, regulManager);
        } else if (rekenTijd.eindDatum.isBefore(START_DMFA)) {
            return new PensioenPijler2Validator2010(constantManager, dmfapplBasisBijdrageService, opper, rekenTijd, regulManager);
        } else if (rekenTijd.eindDatum.isBefore(START_2023)) {
            return new PensioenPijler2ValidatorDmfa(constantManager, dmfapplBasisBijdrageService, opper, rekenTijd, regulManager);
        } else {
            return new PensioenPijler2ValidatorDmfa2023(constantManager, dmfapplBasisBijdrageService, opper, rekenTijd, regulManager);
        }
    }
}
